codeExercises.solution:
import axios from 'axios';

const apiClient = axios.create({
  baseURL: 'https://jsonplaceholder.typicode.com'
});

// Viết code response interceptor của bạn ở đây
apiClient.interceptors.response.use(
  response => {
    // Bất kỳ status code nào nằm trong khoảng 2xx sẽ đi vào đây
    return response;
  },
  error => {
    // Bất kỳ status code nào nằm ngoài khoảng 2xx sẽ đi vào đây
    if (error.response) {
      // Request đã được gửi và server đã trả về với một status code
      // không nằm trong khoảng 2xx
      console.error(`Lỗi API: Status ${error.response.status} - ${error.response.statusText}`);
    } else if (error.request) {
      // Request đã được gửi nhưng không nhận được phản hồi
      console.error('Lỗi mạng: Không nhận được phản hồi từ server.');
    } else {
      // Có lỗi xảy ra khi thiết lập request
      console.error('Lỗi: ', error.message);
    }
    return Promise.reject(error);
  }
);

// Test bằng cách gọi một API không tồn tại
apiClient.get('/posts/99999999');
